import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { Badge } from '@/components/ui/badge'
import useAdminUserStore from '@/stores/useAdminUserStore'

export default function AdminUsers() {
  const { users } = useAdminUserStore()

  return (
    <div className="space-y-6 animate-fade-in relative z-20">
      <div className="mb-8">
        <h1 className="text-3xl font-heading font-bold mb-1">Clientes e Segmentação</h1>
        <p className="text-muted-foreground">
          Gerencie seus clientes e visualize suas tags e histórico.
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Usuários Cadastrados</CardTitle>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Nome</TableHead>
                <TableHead>E-mail</TableHead>
                <TableHead>Tags / Segmentação</TableHead>
                <TableHead className="text-right">Downloads Restantes</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {users.map((user) => (
                <TableRow key={user.id}>
                  <TableCell className="font-medium">{user.name}</TableCell>
                  <TableCell>{user.email}</TableCell>
                  <TableCell>
                    <div className="flex gap-2 flex-wrap">
                      {user.tags?.map((tag) => (
                        <Badge
                          key={tag}
                          variant="secondary"
                          className="bg-primary/10 text-primary hover:bg-primary/20"
                        >
                          {tag}
                        </Badge>
                      ))}
                      {(!user.tags || user.tags.length === 0) && (
                        <span className="text-muted-foreground text-xs italic">Sem tags</span>
                      )}
                    </div>
                  </TableCell>
                  <TableCell className="text-right">
                    {Math.max(0, user.downloadLimit - user.totalDownloads)} / {user.downloadLimit}
                  </TableCell>
                </TableRow>
              ))}
              {users.length === 0 && (
                <TableRow>
                  <TableCell colSpan={4} className="text-center py-6 text-muted-foreground">
                    Nenhum usuário encontrado.
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  )
}
